sql:
SELECT a.common_name 
FROM animals a 
WHERE a.domestic = 1 AND a.catsize = 1;

external_knowledge:
- 'Domesticated' means that the animals are tame and live among or near humans; 
- 'Hair' refers to any growth on the body that resembles hair; 
- 'Mammalia' is a taxonomic rank that includes warm-blooded vertebrates with hair or fur and whose females produce milk to feed their young.

sql:
SELECT common_name
FROM animals
WHERE type = 'mammal' AND lifespan > (SELECT AVG(lifespan) FROM animals);

SELECT common_name, lifespan
FROM animals
WHERE domestic = 1 AND habitat = 'forest' AND lifespan > 30;

SELECT AVG(lifespan) AS average_lifespan
FROM animals
WHERE catsize = 1 AND conservation_status = 'least concern' AND type = 'mammal';

SELECT a.name
FROM animals a
WHERE a.type = 'mammal' AND a.conservation_status = 'endangered';
